import React, {type Ref, useCallback, useMemo, useRef, useState} from 'react';
import {useUploader} from '../MainUploader';
import {useDrop} from 'react-dnd';
import {NativeTypes} from 'react-dnd-html5-backend';
import {checkExtAgainstAccepted} from '@lmb-it/kitsconcerto-types';
import {Button, Flex, Icon, Image, Text} from "../../../_compat";
import {useLanguage} from "../../../_compat";
import {FileUpload} from "primereact/fileupload";

const SingleImageUploader = () => {
    const {t} = useLanguage();
    const {
        onChangeAnyFileUploader,
        acceptedMemes,
        files,
        isClassicUploader,
        onInvalidInput,
        removeFile,
        disabled,
        previewWidth,
        previewHeight,
    } = useUploader();
    const fileUploadRef = useRef<FileUpload>(null);

    const fileId = files.map((_, index) => index);

    const [{isOver, canDrop}, drop] = useDrop(() => ({
        accept: [NativeTypes.FILE],
        canDrop: (item) => {
            if (!(item && typeof item == 'object' && 'files' in item && Array.isArray(item.files) && item.files.length < 2)) {
                return false;
            }
            const firstFile = item.files[0];
            if (firstFile && 'name' in firstFile) {
                const isGranted = checkExtAgainstAccepted(firstFile.name, acceptedMemes);
                if (!isGranted) {
                    onInvalidInput(t('typeNotSupported'));
                }
                return isGranted;
            }
            return true;
        },
        drop: (item) => {
            if (item && typeof item == 'object' && 'files' in item && Array.isArray(item.files) && item.files.length > 0) {
                const files = item.files as File[];
                // @ts-ignore
                onChangeAnyFileUploader(files);
            }
            return item;
        },
        collect: (monitor: any) => ({
            isOver: monitor.isOver(),
            canDrop: monitor.canDrop()
        })
    }));

    const isActive = canDrop && isOver;

    const onClickUpload = () => {
        fileUploadRef.current && fileUploadRef.current.getInput()?.click();
    };

    const currentFileName = useMemo(() => {
        if (files.length > 0) return files[0]?.name;
        return null;
    }, [files]);

    const isImage = !!currentFileName;

    const ImagePreview = useCallback(() => {
        // eslint-disable-next-line react-hooks/rules-of-hooks
        const [imageToPreview, setImageToPreview] = useState<any>('');

        let ImageSrc = imageToPreview;
        let imageName: string | undefined;

        if (files.length > 0) {
            const file = files[0];
            if (file?.file instanceof File) {
                const reader = new FileReader();
                reader.readAsDataURL(file.file);
                reader.onloadend = function () {
                    setImageToPreview(reader.result);
                };
            } else if (typeof file?.file == 'string') {
                const isGranted = currentFileName && checkExtAgainstAccepted(currentFileName, acceptedMemes);
                if (!isGranted) {
                    ImageSrc = file?.file;
                    imageName = file?.name;
                }
            } else {
                const isGranted = currentFileName && checkExtAgainstAccepted(currentFileName, acceptedMemes);
                if (isGranted) {
                    ImageSrc = file?.file.uri;
                }
            }
        }
        return (
            <Flex
                justifyContent={'center'}
                alignItems={'center'}
                w={previewWidth ?? 'full'}
                {...(previewHeight ? {h: previewHeight} : {})}
                {...(!previewHeight && !previewWidth ? {aspectRatio: 2} : {})}
            >
                <Image src={ImageSrc}
                       alt="Preview"
                       preview
                       style={{
                           objectFit: previewWidth || previewHeight ? 'contain' : 'cover',
                           width: '100%',
                           height: '100%',
                       }}
                />
                {imageName && (
                    <Text position={'absolute'} bgColor={'surface-100'} bottom={0} p={10}
                          fontSize={12} color={'text-secondary'}>{imageName}</Text>
                )}
                <Button aria-label={t('remove')}
                        style={{
                            position: 'absolute',
                            right: 0,
                            top: 0,
                        }}
                        size={'sm'}
                        severity={'danger'}
                        icon={'pi pi-times'}
                        onClick={(event: any) => {
                            event.stopPropagation();
                            if (fileUploadRef.current) {
                                fileUploadRef.current.clear();
                            }
                            if (fileId.length > 0 && fileId[0] !== undefined) {
                                removeFile(fileId[0])();
                            }
                        }}/>
            </Flex>
        );
    }, [files]);

    // Hidden file input
    const hiddenUpload = (
        <FileUpload
            ref={fileUploadRef}
            mode="basic"
            auto
            accept={acceptedMemes.length > 0 ? acceptedMemes.join(',') : 'images/*'}
            customUpload
            style={{display: 'none'}}
            chooseLabel={t('filesSelected', files.length)}
            uploadHandler={(event) => {
                // @ts-ignore
                onChangeAnyFileUploader(event.files)
            }}
        />
    );

    if (isClassicUploader) {
        return (
            <Flex w={'full'}
                  justifyContent={'space-between'}
                  alignItems={'center'}
                  gap={8}
                  flexDirection={'row'}
                  ref={drop as unknown as Ref<HTMLDivElement>}>
                <FileUpload
                    ref={fileUploadRef}
                    mode="basic"
                    auto
                    accept={acceptedMemes.length > 0 ? acceptedMemes.join(',') : 'images/*'}
                    customUpload
                    chooseLabel={isImage ? t('changeImage') : t('chooseImage')}
                    className={'w-full'}
                    uploadHandler={(event) => {
                        // @ts-ignore
                        onChangeAnyFileUploader(event.files)
                    }}
                />
                <Button
                    aria-label={t('remove')}
                    disabled={!currentFileName}
                    severity={'danger'}
                    size={'sm'}
                    icon={'pi pi-times'}
                    onClick={(event: any) => {
                        event.stopPropagation();
                        if (fileUploadRef.current) {
                            fileUploadRef.current.clear()
                        }
                        if (fileId.length > 0 && fileId[0] !== undefined) {
                            removeFile(fileId[0])();
                        }
                    }}/>
            </Flex>
        );
    }

    // Non-classic mode: dashed drop zone with upload icon + phrase
    return (
        <Flex flexDirection={'column'}
              className={disabled ? 'p-disabled' : ''}
              w={'full'}
              borderRadius={'inherit'}
              alignItems={'center'}
              gap={8}>
            {hiddenUpload}

            <Flex
                flex={1}
                w={'full'}
                flexDirection={'column'}
                onClick={onClickUpload}
                cursor={'pointer'}
                borderRadius={'inherit'}
                position={'relative'}
                ref={drop as unknown as Ref<HTMLDivElement>}>

                {isImage && <ImagePreview/>}

                {!isImage && (
                    <Flex
                        borderW={2}
                        borderStyle={'dashed'}
                        borderColor={isActive ? 'brand.500' : 'surface-300'}
                        bgColor={isActive ? 'highlight-bg' : 'transparent'}
                        borderRadiusLeft={'lg'}
                        borderRadiusRight={'lg'}
                        borderRadius={'inherit'}
                        alignItems={'center'}
                        justifyContent={'center'}
                        flexDirection={'column'}
                        py={32}
                        px={16}
                        gap={8}
                        w={'full'}
                        className={'dropping_area'}
                        style={{transition: 'border-color 0.2s, background-color 0.2s'}}>
                        <Icon name="cloud-upload" size={'lg'} color={isActive ? 'brand.500' : 'surface-300'} />
                        <Text fontSize={14} color={'text-secondary'} textAlign={'center'}>
                            {isActive ? t('filesBeingDropped') : t('clickOrDragToUpload')}
                        </Text>
                    </Flex>
                )}
            </Flex>
        </Flex>
    );
};

export default SingleImageUploader;
